use std::collections::{BTreeMap, BTreeSet};

use crate::core_a::R0;

pub fn fold_b(a: &[R0], cap: usize) -> Vec<R0> {
    let cap = cap.max(1);
    // Collect all distinct turns where items become ready
    let mut all_turns: BTreeSet<u64> = BTreeSet::new();
    for row in a {
        all_turns.insert(row.base_turn);
    }

    let mut accepted: Vec<R0> = Vec::new();
    let mut accepted_names: BTreeSet<String> = BTreeSet::new();

    // We process turn by turn; overflow from earlier turns carries forward
    let mut turn_counter: u64 = 0;
    let max_turn = all_turns.iter().copied().max().unwrap_or(0);

    // Keep going until all items are accepted
    let mut remaining: Vec<R0> = a.to_vec();
    // Deduplicate: keep first occurrence by ident (plan-file order = seq)
    {
        let mut seen = BTreeSet::new();
        remaining.retain(|r| seen.insert(r.task_name.clone()));
    }
    remaining.sort_by_key(|r| r.seq);

    while !remaining.is_empty() {
        // Find items ready this turn (base_turn <= turn_counter)
        // Group ready items by lane
        let mut by_lane: BTreeMap<String, Vec<usize>> = BTreeMap::new();
        for (i, row) in remaining.iter().enumerate() {
            if row.base_turn <= turn_counter {
                by_lane.entry(row.lane_name.clone()).or_default().push(i);
            }
        }

        if by_lane.is_empty() {
            // Skip to next turn that has ready items
            if let Some(&next) = all_turns.iter().find(|&&t| t > turn_counter) {
                turn_counter = next;
                continue;
            } else {
                // No more turns with new arrivals, but if there are remaining items
                // they should have already been ready. This shouldn't happen.
                break;
            }
        }

        let mut to_remove: BTreeSet<usize> = BTreeSet::new();
        for (_lane, indices) in &by_lane {
            // indices are already in seq order since remaining is sorted by seq
            for &idx in indices.iter().take(cap) {
                let mut row = remaining[idx].clone();
                row.turn = turn_counter;
                accepted.push(row);
                to_remove.insert(idx);
            }
        }

        // Remove accepted items from remaining (in reverse order to preserve indices)
        let mut remove_vec: Vec<usize> = to_remove.into_iter().collect();
        remove_vec.sort_unstable_by(|a, b| b.cmp(a));
        for idx in remove_vec {
            remaining.remove(idx);
        }

        turn_counter += 1;
    }

    // Sort by (turn, lane_name, seq)
    accepted.sort_by(|left, right| {
        left.turn.cmp(&right.turn)
            .then(left.lane_name.cmp(&right.lane_name))
            .then(left.seq.cmp(&right.seq))
    });
    accepted
}
